#include<bits/stdc++.h>
using namespace std;
struct FHQ_Treap
{
    struct node
    {
        int l,r;
        int val,key;
        int siz,rev_tag;
    }t[100010];
    int cnt,root;
    stack<int> s;
    FHQ_Treap():cnt(0){}
    int newnode(int v)
    {
        int x;
        if(!s.empty())
        {
            x=s.top();
            s.pop();
        }
        else
        {
            x=++cnt;
        }
        t[x].l=t[x].r=0;
        t[x].val=v;
        t[x].key=rand();
        t[x].siz=1;
        return x;
    }
    void pushup(int x)
    {
        t[x].siz=t[t[x].l].siz+t[t[x].r].siz+1;
    }
    void pushrev(int x)
    {
        swap(t[x].l,t[x].r);
        t[x].rev_tag^=1;
    }
    void pushdown(int x)
    {
        if(t[x].rev_tag)
        {
            pushrev(t[x].l);
            pushrev(t[x].r);
            t[x].rev_tag=0;
        }
    }
    void split(int p,int v,int &x,int &y)
    {
        if(p==0)
        {
            x=y=0;
            return;
        }
        pushdown(p);
        if(t[t[p].l].siz+1<=v)
        {
            x=p;
            split(t[p].r,v-t[t[p].l].siz-1,t[p].r,y);
        }
        else
        {
            y=p;
            split(t[p].l,v,x,t[p].l);
        }
        pushup(p);
    }
    int merge(int x,int y)
    {
        if(x==0||y==0)
        {
            return x+y;
        }
        pushdown(x);
        pushdown(y);
        if(t[x].key<t[y].key)
        {
            t[x].r=merge(t[x].r,y);
            pushup(x);
            return x;
        }
        else
        {
            t[y].l=merge(x,t[y].l);
            pushup(y);
            return y;
        }
    }
    void insert(int v)
    {
        int x=newnode(v);
        root=merge(root,x);
    }
    void del(int p)
    {
        int x,y,z;
        split(root,p,x,z);
        split(x,p-1,x,y);
        root=merge(x,z);
    }
    int getval(int p)
    {
        int x,y,z;
        split(root,p,x,z);
        split(x,p-1,x,y);
        int ans=t[y].val;
        root=merge(merge(x,y),z);
        return ans;
	}
	void clear()
	{
		root=cnt=0;
	}
}t;
int main()
{
	int T;
	scanf("%d",&T);
	for(int _=1;_<=T;_++)
	{
		int n;
		scanf("%d",&n);
		t.clear();
		for(int i=1;i<=n;i++)
		{
			int x;
			scanf("%d",&x);
			t.insert(x);
		}
		printf("Case #%d: ",_);
		int flag=1;
		int l=1,r=n;
		for(int i=1;i<=n;i++)
		{
			int p=(n-i+1-1)/2+1;
			if(t.getval(p)==r)
			{
				r--;
				t.del(p);
			}
			else if(t.getval(p)==l)
			{
				l++;
				t.del(p);
			}
			else
			{
				flag=0;
				break;
			}
		}
		if(flag)
		{
			printf("YES\n");
		}
		else
		{
			printf("NO\n");
		}
	}
	return 0;
}
